// URL 받기
const inputUrl = $input.first().json.query.url;
if (!inputUrl) {
  return [{ json: { error: 'URL이 필요합니다.' } }];
}
const url = /^https?:\/\//i.test(inputUrl) ? inputUrl : `https://${inputUrl}`;

// HTTP 상태코드 체크
async function checkHttpStatus(url) {
  const STATUS_MESSAGES = {
    200: '정상 접속 - 요청된 웹 페이지를 정상적으로 응답',
    301: '영구 이동 - URL이 완전히 전환됨',
    302: '임시 이동',
    303: '임시 이동 (See Other)',
    307: '임시 리다이렉트',
    308: '영구 리다이렉트',
    400: '잘못된 요청 - HTTP 문법 오류',
    401: '인증 필요 - 접근 자격 없음',
    403: '접근 금지 - 권한 없음',
    404: '페이지 없음 - 존재하지 않는 페이지',
    500: '서버 오류 - 서버 설정/프로그램 오류',
    503: '서비스 불가 - 서버 과부하',
  };
  try {
    const res = await fetch(url, { redirect: 'manual', signal: AbortSignal.timeout(10000) });
    const code = res.status;
    let message = STATUS_MESSAGES[code];
    if (!message) {
      if (code >= 400 && code < 500) message = '클라이언트 오류';
      else if (code >= 500) message = '서버 오류';
      else message = '알 수 없는 응답';
    }
    const pass = code >= 200 && code < 400;
    const location = res.headers.get('location') || null;
    const details = [];
    if (code >= 200 && code < 300) {
      details.push({ type: 'info', text: `HTTP ${code} (200번대) - ${message}` });
    } else if (code >= 300 && code < 400) {
      details.push({ type: 'info', text: `HTTP ${code} (300번대) - ${message}` });
    } else {
      details.push({ type: 'warn', text: `HTTP ${code} - ${message}` });
    }
    if (location) details.push({ type: 'info', text: `리다이렉트 대상: ${location}` });
    if (code >= 300 && code < 400) {
      details.push({ type: 'tip', text: '301(영구 이동)은 SEO에 유리합니다. 302~307은 임시 이동으로, 검색엔진이 원본 URL을 유지합니다. 영구적으로 이전한 경우 301을 사용하세요.' });
    }
    if (code >= 400) {
      details.push({ type: 'tip', text: `${code >= 500 ? '서버 오류를 확인하고 수정하세요.' : 'URL이 올바른지, 페이지가 존재하는지 확인하세요.'} 오류 페이지는 검색 색인에서 제외됩니다.` });
    }
    return { code, message, pass, location, details };
  } catch (e) {
    return { code: null, message: `접속 실패 - ${e.message}`, pass: false, location: null, details: [] };
  }
}

// HTML 가져오기
async function fetchHtml(url) {
  try {
    const res = await fetch(url, {
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; SEOChecker/1.0)' },
      signal: AbortSignal.timeout(10000)
    });
    const ct = res.headers.get('content-type') || '';
    if (!ct.includes('text/html')) return { html: null, contentType: ct };
    const html = await res.text();
    return { html, contentType: ct };
  } catch (e) {
    return { html: null, contentType: null, error: e.message };
  }
}

// 간단 HTML 파싱 헬퍼
function getMetaContent(html, attr, value) {
  const regex = new RegExp(`<meta[^>]+${attr}\\s*=\\s*["']${value}["'][^>]*>`, 'i');
  const match = html.match(regex);
  if (!match) return null;
  const contentMatch = match[0].match(/content\s*=\s*["']([^"']*)["']/i);
  return contentMatch ? contentMatch[1].trim() : null;
}

function getMetaByName(html, name) {
  const regex = new RegExp(`<meta[^>]+name\\s*=\\s*["']${name}["'][^>]*>`, 'i');
  const match = html.match(regex);
  if (!match) return null;
  const contentMatch = match[0].match(/content\s*=\s*["']([^"']*)["']/i);
  return contentMatch ? contentMatch[1].trim() : null;
}

function getTitle(html) {
  const match = html.match(/<title[^>]*>([^<]*)<\/title>/i);
  return match ? match[1].trim() : null;
}

function getRobotsMetaTags(html) {
  const tags = [];
  const regex = /<meta[^>]+name\s*=\s*["'](robots|googlebot|yeti)["'][^>]*>/gi;
  let m;
  while ((m = regex.exec(html)) !== null) {
    const name = m[1];
    const contentMatch = m[0].match(/content\s*=\s*["']([^"']*)["']/i);
    tags.push({ name, content: contentMatch ? contentMatch[1] : '' });
  }
  return tags;
}

function detectRepeatedKeywords(text) {
  const words = text.split(/\s+/).filter(w => w.length > 1);
  const freq = {};
  for (const w of words) {
    const key = w.toLowerCase();
    freq[key] = (freq[key] || 0) + 1;
  }
  return Object.entries(freq).filter(([, c]) => c >= 3).map(([w]) => w);
}

// robots.txt 체크
async function checkRobotsTxt(url) {
  try {
    const u = new URL(url);
    const robotsUrl = `${u.protocol}//${u.host}/robots.txt`;
    const res = await fetch(robotsUrl, { signal: AbortSignal.timeout(10000) });
    const code = res.status;
    const details = [];
    if (code >= 500) {
      return { pass: false, message: `robots.txt 서버 오류 (${code})`, details: [{ type: 'warn', text: `robots.txt 요청 시 서버 오류 발생 (HTTP ${code})` }] };
    }
    if (code >= 400) {
      details.push({ type: 'warn', text: 'robots.txt 파일 없음' });
      details.push({ type: 'tip', text: '웹사이트 루트에 robots.txt 파일을 추가하세요. 검색엔진 크롤러에게 어떤 페이지를 수집할 수 있는지 안내하는 역할을 합니다.' });
      return { pass: false, message: 'robots.txt 없음', details };
    }
    const text = await res.text();
    const ct = res.headers.get('content-type') || '';
    if (!ct.includes('text/plain')) {
      details.push({ type: 'warn', text: `Content-Type이 text/plain이 아님 (${ct})` });
    }
    details.push({ type: 'info', text: 'robots.txt 존재' });
    const lines = text.split('\n').map(l => l.trim().toLowerCase());
    const hasDisallowAll = lines.some(l => l === 'disallow: /');
    const hasAllowAll = lines.some(l => l === 'allow: /');
    if (hasDisallowAll && !hasAllowAll) {
      details.push({ type: 'warn', text: 'Disallow: / 설정으로 모든 크롤러 차단 중' });
    }
    const hasSitemap = lines.some(l => l.startsWith('sitemap:'));
    if (hasSitemap) {
      details.push({ type: 'info', text: 'Sitemap 경로 포함됨' });
    } else {
      details.push({ type: 'info', text: 'Sitemap 경로 없음 - robots.txt에 Sitemap 경로를 추가하면 검색엔진이 페이지를 더 효율적으로 발견할 수 있습니다.' });
    }
    return { pass: true, message: 'robots.txt 정상', details };
  } catch (e) {
    return { pass: false, message: `접속 실패 - ${e.message}`, details: [] };
  }
}

// 로봇 메타 태그 체크
function checkRobotsMeta(html) {
  if (!html) return { pass: false, found: false, message: '접속 실패', details: [] };
  const tags = getRobotsMetaTags(html);
  if (tags.length === 0) {
    return {
      pass: true, found: false,
      message: '기본값 index, follow 적용',
      details: [{ type: 'info', text: '네이버 로봇이 사이트를 수집할 수 있고 검색 결과에 노출할 수 있습니다.' }]
    };
  }
  const details = [];
  let overallNoindex = false;
  let overallNofollow = false;
  for (const tag of tags) {
    const directives = tag.content.split(',').map(d => d.trim().toLowerCase()).filter(Boolean);
    const hasNoindex = directives.includes('noindex');
    const hasNofollow = directives.includes('nofollow');
    const hasNone = directives.includes('none');
    const hasIndex = directives.includes('index');
    const hasFollow = directives.includes('follow');
    const hasAll = directives.includes('all');
    if (hasNoindex || hasNone) {
      details.push({ type: 'warn', text: 'noindex: 검색 결과에서 제외됨' });
      overallNoindex = true;
    } else if (hasIndex || hasAll) {
      details.push({ type: 'info', text: 'index: 검색 색인 대상' });
    }
    if (hasNofollow || hasNone) {
      details.push({ type: 'warn', text: 'nofollow: 페이지 내 링크 미수집' });
      overallNofollow = true;
    } else if (hasFollow || hasAll) {
      details.push({ type: 'info', text: 'follow: 페이지 내 링크 수집' });
    }
  }
  const pass = !overallNoindex && !overallNofollow;
  if (pass) {
    details.unshift({ type: 'info', text: '네이버 로봇이 사이트를 수집할 수 있고 검색 결과에 노출할 수 있습니다.' });
  }
  const statusParts = [];
  if (overallNoindex) statusParts.push('noindex');
  if (overallNofollow) statusParts.push('nofollow');
  const message = pass
    ? `로봇 메타 태그 있음 - 색인 허용`
    : `로봇 메타 태그 있음 - 색인 제외 (${statusParts.join(', ')})`;
  return { pass, found: true, message, details };
}

// 타이틀 체크
function checkTitleTag(html) {
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const title = getTitle(html);
  const details = [];
  let pass = true;
  if (!title) {
    return {
      pass: false, message: 'title 태그 없음 - 검색 노출에 불이익',
      details: [{ type: 'tip', text: '<head> 태그 안에 <title>페이지 제목</title>을 추가하세요.' }]
    };
  }
  details.push({ type: 'info', text: `title: "${title}"` });
  const len = title.length;
  if (len > 100) {
    details.push({ type: 'warn', text: `제목이 너무 김 (${len}자)` });
    details.push({ type: 'tip', text: '검색 결과에서 제대로 표시될 수 있도록 제목을 40자 이내로 줄여주세요.' });
    pass = false;
  } else if (len > 40) {
    details.push({ type: 'warn', text: `제목이 다소 긴 편 (${len}자)` });
    details.push({ type: 'tip', text: '사용자가 쉽게 사이트를 파악할 수 있도록 40자 이내로 제목을 작성해주세요.' });
    pass = false;
  } else {
    details.push({ type: 'info', text: `제목 길이 양호 (${len}자)` });
  }
  const repeated = detectRepeatedKeywords(title);
  if (repeated.length > 0) {
    details.push({ type: 'warn', text: `반복 키워드 감지: ${repeated.map(w => `"${w}"`).join(', ')}` });
    pass = false;
  }
  const warn = !pass && len > 40;
  const message = pass ? `title 태그 정상 (${len}자)` : `title 태그 문제 있음 (${len}자)`;
  return { pass, warn, message, details };
}

// 메타 디스크립션 체크
function checkMetaDescription(html) {
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const desc = getMetaByName(html, 'description');
  const ogDesc = getMetaContent(html, 'property', 'og:description');
  const title = getTitle(html);
  const details = [];
  let pass = true;
  if (!desc) {
    details.push({ type: 'warn', text: 'meta description 없음 - 검색 스니펫 자동 추출에 의존하게 됨' });
    details.push({ type: 'tip', text: '<head> 태그 안에 <meta name="description" content="페이지 설명">을 추가하세요.' });
    if (ogDesc) {
      details.push({ type: 'info', text: `og:description: "${ogDesc}"` });
      details.push({ type: 'warn', text: 'og:description만 있음 - meta description도 별도 추가 권장' });
    } else {
      details.push({ type: 'warn', text: 'og:description도 없음 - 소셜 공유 및 검색 활용도 저하 가능' });
    }
    return { pass: false, message: 'meta description 없음', details };
  }
  details.push({ type: 'info', text: `description: "${desc}"` });
  const len = desc.length;
  if (len > 300) {
    details.push({ type: 'warn', text: `설명이 너무 김 (${len}자)` });
    details.push({ type: 'tip', text: '설명을 160자 이내로 줄여주세요.' });
    pass = false;
  } else if (len > 160) {
    details.push({ type: 'warn', text: `설명이 다소 긴 편 (${len}자)` });
    details.push({ type: 'tip', text: '160자 이내로 작성하면 검색 결과에서 설명이 잘리지 않습니다.' });
    pass = false;
  } else if (len > 80) {
    details.push({ type: 'warn', text: `설명이 다소 긴 편 (${len}자)` });
    details.push({ type: 'tip', text: '사용자가 쉽게 사이트를 파악할 수 있도록 80자 이내로 설명문을 작성해주세요.' });
    pass = false;
  } else {
    details.push({ type: 'info', text: `설명 길이 양호 (${len}자)` });
  }
  if (title && desc === title) {
    details.push({ type: 'warn', text: '제목(title)과 설명이 동일 - 검색 노출 불이익 가능' });
    pass = false;
  }
  const repeated = detectRepeatedKeywords(desc);
  if (repeated.length > 0) {
    details.push({ type: 'warn', text: `반복 키워드 감지: ${repeated.map(w => `"${w}"`).join(', ')}` });
    pass = false;
  }
  if (ogDesc) {
    if (ogDesc !== desc) details.push({ type: 'info', text: 'og:description과 다름' });
  } else {
    details.push({ type: 'warn', text: 'og:description 없음 - 소셜 공유 및 검색 활용도 저하 가능' });
  }
  const warn = !pass && len > 80;
  const message = pass ? `meta description 정상 (${len}자)` : `meta description 문제 있음 (${len}자)`;
  return { pass, warn, message, details };
}

// og:title 체크
function checkOgTitle(html) {
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const ogTitle = getMetaContent(html, 'property', 'og:title');
  const title = getTitle(html);
  const details = [];
  let pass = true;
  if (!ogTitle) {
    details.push({ type: 'warn', text: 'og:title 태그 없음 - 소셜 공유 및 네이버 검색 활용도 저하 가능' });
    details.push({ type: 'tip', text: '<meta property="og:title" content="페이지 제목">을 <head> 안에 추가하세요.' });
    if (title) details.push({ type: 'info', text: `대신 title 태그 존재: "${title}"` });
    return { pass: false, message: 'og:title 없음', details };
  }
  details.push({ type: 'info', text: `og:title: "${ogTitle}"` });
  const len = ogTitle.length;
  if (len > 100) {
    details.push({ type: 'warn', text: `og:title이 너무 김 (${len}자)` });
    details.push({ type: 'tip', text: '80자 이내로 줄여주세요.' });
    pass = false;
  } else if (len > 80) {
    details.push({ type: 'warn', text: `og:title이 다소 긴 편 (${len}자)` });
    details.push({ type: 'tip', text: '80자 이내로 작성하면 소셜 공유 미리보기에서 제목이 온전히 표시됩니다.' });
    pass = false;
  } else if (len > 40) {
    details.push({ type: 'warn', text: `og:title이 다소 긴 편 (${len}자)` });
    details.push({ type: 'tip', text: '사용자가 쉽게 사이트를 파악할 수 있도록 40자 이내로 제목을 작성해주세요.' });
    pass = false;
  } else {
    details.push({ type: 'info', text: `og:title 길이 양호 (${len}자)` });
  }
  const repeated = detectRepeatedKeywords(ogTitle);
  if (repeated.length > 0) {
    details.push({ type: 'warn', text: `반복 키워드 감지: ${repeated.map(w => `"${w}"`).join(', ')}` });
    pass = false;
  }
  if (title && ogTitle !== title) {
    details.push({ type: 'info', text: `title 태그와 다름: "${title}"` });
  } else if (title && ogTitle === title) {
    details.push({ type: 'info', text: 'title 태그와 동일' });
  }
  const warn = !pass && len > 40;
  const message = pass ? `og:title 정상 (${len}자)` : `og:title 문제 있음 (${len}자)`;
  return { pass, warn, message, details };
}

// og:description 체크
function checkOgDescription(html) {
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const ogDesc = getMetaContent(html, 'property', 'og:description');
  const metaDesc = getMetaByName(html, 'description');
  const details = [];
  let pass = true;
  if (!ogDesc) {
    details.push({ type: 'warn', text: 'og:description 태그 없음 - 소셜 공유 및 네이버 검색 활용도 저하 가능' });
    details.push({ type: 'tip', text: '<meta property="og:description" content="페이지 설명">을 <head> 안에 추가하세요.' });
    if (metaDesc) details.push({ type: 'info', text: `대신 meta description 존재: "${metaDesc}"` });
    return { pass: false, message: 'og:description 없음', details };
  }
  details.push({ type: 'info', text: `og:description: "${ogDesc}"` });
  const len = ogDesc.length;
  if (len > 300) {
    details.push({ type: 'warn', text: `og:description이 너무 김 (${len}자)` });
    details.push({ type: 'tip', text: '200자 이내로 줄여주세요.' });
    pass = false;
  } else if (len > 200) {
    details.push({ type: 'warn', text: `og:description이 다소 긴 편 (${len}자)` });
    details.push({ type: 'tip', text: '200자 이내로 작성하면 소셜 공유 미리보기에서 설명이 온전히 표시됩니다.' });
    pass = false;
  } else if (len > 80) {
    details.push({ type: 'warn', text: `og:description이 다소 긴 편 (${len}자)` });
    details.push({ type: 'tip', text: '사용자가 쉽게 사이트를 파악할 수 있도록 80자 이내로 설명문을 작성해주세요.' });
    pass = false;
  } else if (len < 10) {
    details.push({ type: 'warn', text: `og:description이 너무 짧음 (${len}자)` });
    pass = false;
  } else {
    details.push({ type: 'info', text: `og:description 길이 양호 (${len}자)` });
  }
  const repeated = detectRepeatedKeywords(ogDesc);
  if (repeated.length > 0) {
    details.push({ type: 'warn', text: `반복 키워드 감지: ${repeated.map(w => `"${w}"`).join(', ')}` });
    pass = false;
  }
  if (metaDesc && ogDesc === metaDesc) {
    details.push({ type: 'info', text: 'meta description과 동일' });
  } else if (metaDesc) {
    details.push({ type: 'info', text: 'meta description과 다름' });
  }
  const warn = !pass && len > 80;
  const message = pass ? `og:description 정상 (${len}자)` : `og:description 문제 있음 (${len}자)`;
  return { pass, warn, message, details };
}

// 메인 실행
const [http, robots, htmlData] = await Promise.all([
  checkHttpStatus(url),
  checkRobotsTxt(url),
  fetchHtml(url)
]);

const html = htmlData.html;
const robotsMeta = checkRobotsMeta(html);
const titleResult = checkTitleTag(html);
const descResult = checkMetaDescription(html);
const ogTitleResult = checkOgTitle(html);
const ogDescResult = checkOgDescription(html);

return [{
  json: {
    url,
    checks: [
      { name: 'HTTP 상태코드', key: 'http', ...http },
      { name: 'robots.txt', key: 'robots', ...robots },
      { name: '로봇 메타 태그', key: 'robotsMeta', ...robotsMeta },
      { name: '페이지 제목 (title)', key: 'title', ...titleResult },
      { name: '사이트 설명 (meta description)', key: 'desc', ...descResult },
      { name: 'Open Graph 제목 (og:title)', key: 'ogTitle', ...ogTitleResult },
      { name: 'Open Graph 설명 (og:description)', key: 'ogDesc', ...ogDescResult }
    ]
  }
}];
